// ProductTransitionMultiError is an error wrapping multiple validation errors
// returned by ProductTransition.ValidateAll() if the designated constraints
// aren't met.
type ProductTransitionMultiError []error

// Error returns a concatenation of all the error messages it wraps.
func (m ProductTransitionMultiError) Error() string {
	msgs := make([]string, 0, len(m))
	for _, err := range m {
		msgs = append(msgs, err.Error())
	}
	return strings.Join(msgs, "; ")
}

// AllErrors returns a list of validation violation errors.
func (m ProductTransitionMultiError) AllErrors() []error { return m }

// ProductTransitionValidationError is the validation error returned by
// ProductTransition.Validate if the designated constraints aren't met.
type ProductTransitionValidationError struct {
	field  string
	reason string
	cause  error
	key    bool
}

// Field function returns field value.
func (e ProductTransitionValidationError) Field() string { return e.field }

// Reason function returns reason value.
func (e ProductTransitionValidationError) Reason() string { return e.reason }

// Cause function returns cause value.
func (e ProductTransitionValidationError) Cause() error { return e.cause }

// Key function returns key value.
func (e ProductTransitionValidationError) Key() bool { return e.key }

// ErrorName returns error name.
func (e ProductTransitionValidationError) ErrorName() string {
	return "ProductTransitionValidationError"
}

// Error satisfies the builtin error interface
func (e ProductTransitionValidationError) Error() string {
	cause := ""
	if e.cause != nil {
		cause = fmt.Sprintf(" | caused by: %v", e.cause)
	}

	key := ""
	if e.key {
		key = "key for "
	}

	return fmt.Sprintf(
		"invalid %sProductTransition.%s: %s%s",
		key,
		e.field,
		e.reason,
		cause)
}

var _ error = ProductTransitionValidationError{}

var _ interface {
	Field() string
	Reason() string
	Key() bool
	Cause() error
	ErrorName() string
} = ProductTransitionValidationError{}
